+export interface RetryOpts { retries: number; baseDelay: number; factor?: number; maxDelay?: number; signal?: AbortSignal; }
+export async function retry<T>(fn: () => Promise<T>, opts: RetryOpts): Promise<T> {
+  const { retries, baseDelay, factor = 2, maxDelay = 30000, signal } = opts;
+  let lastErr: unknown;
+  for (let attempt = 0; attempt <= retries; attempt++) {
+    if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
+    try { return await fn(); } catch (err) {
+      lastErr = err;
+      if (attempt === retries) break;
+      const capped = Math.min(maxDelay, baseDelay * factor ** attempt);
+      const delay = Math.random() * capped; // full jitter
+      await new Promise<void>((res, rej) => {
+        const t = setTimeout(res, delay);
+        signal?.addEventListener('abort', () => { clearTimeout(t); rej(new DOMException('aborted', 'AbortError')); }, { once: true });
+      });
+    }
+  }
+  throw lastErr;
+}
